mapper.select:
select *from( SELECT w.*,
case when w.type = 2 then
(select co.phone from coach co where co.coachId = w.userId)
else (select ui.phone from user_info ui where ui.userId=w.userId) end as phone
FROM wallet_detail w where w.type in (1,2) AND w.status in (1,2,3)) r

    
        AND r.realName LIKE concat('%',#{userName},'%')
    
    
        AND r.phone LIKE concat('%',#{phone},'%')
    
    
        AND r.orderNo LIKE concat('%',#{orderNo},'%')
    
    
        AND r.type =#{type}
    
    
        AND r.status =#{status}
    
    
        AND r.checkedTime BETWEEN #{sdate} AND #{edate}
    


    
        order by ${sidx} ${order}
    
    
        order by createTime desc
    


    limit #{offset}, #{limit}

SELECT count(1) from( SELECT w.*, case when w.type = 2 then (select co.phone from coach co where co.coachId = w.userId) else (select ui.phone from user_info ui where ui.userId=w.userId) end as phone FROM wallet_detail w WHERE w.type in (1,2) and w.status in (1,2,3)) r
AND r.realName LIKE concat('%',#{userName},'%')
AND r.phone LIKE concat('%',#{phone},'%')
AND r.orderNo LIKE concat('%',#{orderNo},'%')
AND r.type =#{type}
AND r.status =#{status}
AND r.checkedTime BETWEEN #{sdate} AND #{edate}
